import React, { useEffect, useState, useRef, useCallback } from "react";
import { Link } from "react-router-dom";

// استيراد المكونات من مسارات مشروع Notus React
import Navbar from "components/Navbars/AuthNavbar.js";
import Footer from "components/Footers/Footer.js";

// ============ TextRotate Component (نسخة خفيفة بدون framer-motion) ============
const TextRotate = ({ texts, rotationInterval = 2000, auto = true }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isAnimating, setIsAnimating] = useState(false);

  const nextText = useCallback(() => {
    setIsAnimating(true);
    setTimeout(() => {
      setCurrentIndex((prev) => (prev + 1) % texts.length);
      setTimeout(() => setIsAnimating(false), 100);
    }, 200);
  }, [texts.length]);

  useEffect(() => {
    if (!auto) return;
    const intervalId = setInterval(nextText, rotationInterval);
    return () => clearInterval(intervalId);
  }, [nextText, rotationInterval, auto]);

  return (
    <div className="relative overflow-hidden inline-block">
      <div
        className={`transition-all duration-500 ease-out transform ${
          isAnimating ? "opacity-0 -translate-y-4" : "opacity-100 translate-y-0"
        }`}
      >
        <span className="inline-block whitespace-nowrap">
          {texts[currentIndex]}
        </span>
      </div>
    </div>
  );
};

// ============ صفحة Landing الرئيسية ============
export default function Landing() {
  const texts = [
    "Hello",
    "Bonjour",
    "Ciao",
    "Hola",
    "こんにちは",
    "你好",
    "안녕하세요",
    "नमस्ते",
    "مرحبا",
  ];

  const textRotateRef = useRef(null);

  return (
    <>
      <Navbar transparent />
      <main>
        <div className="relative pt-16 pb-32 flex content-center items-center justify-center min-h-screen">
          <div
            className="absolute top-0 w-full h-full bg-center bg-cover"
            style={{
              backgroundImage:
                "url('https://t4.ftcdn.net/jpg/09/09/79/85/360_F_909798513_DhTQUUB8Sexbj5rBgsz5qwkarSwvQ3mA.jpg')",
            }}
          >
            <div className="absolute inset-0 bg-black bg-opacity-50"></div>
          </div>

          <div className="container relative mx-auto">
            <div className="items-center flex flex-wrap">
              <div className="w-full lg:w-6/12 px-4 ml-auto mr-auto text-center">
                <div className="pr-12">
                  {/* استخدام TextRotate */}
                  <h1 className="text-white font-semibold text-5xl">
                    <TextRotate
                      ref={textRotateRef}
                      texts={texts}
                      rotationInterval={2000}
                      auto={true}
                    />
                  </h1>

                  <p className="mt-4 text-lg text-blueGray-200">
                    Welcome to our website
                  </p>

                  {/* أزرار تحكم اختيارية */}
                  <div className="mt-8 flex justify-center gap-4">
                    <button
                      onClick={() => {
                        // يمكن إضافة منطق التحكم هنا إذا أردت
                      }}
                      className="px-4 py-2 bg-white bg-opacity-20 hover:bg-opacity-30 rounded-lg text-white transition-all"
                    >
                      Previous
                    </button>
                    <button
                      onClick={() => {
                        // يمكن إضافة منطق التحكم هنا إذا أردت
                      }}
                      className="px-4 py-2 bg-white bg-opacity-20 hover:bg-opacity-30 rounded-lg text-white transition-all"
                    >
                      Next
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>
      <Footer />
    </>
  );
}
